1	.page { padding: 24rpx; }
2	.header-date { font-size: 28rpx; color: #78716c; }
3	.header-title { font-size: 52rpx; font-weight: bold; margin-top: 8rpx; }
4	.progress-card {
5	  background: #fff; border-radius: 24rpx; padding: 32rpx;
6	  display: flex; align-items: center; gap: 32rpx; margin-top: 24rpx;
7	  box-shadow: 0 2rpx 16rpx rgba(0,0,0,0.04);
8	}
9	.progress-ring { position: relative; width: 140rpx; height: 140rpx; }
10	.progress-pct { position: absolute; top: 50%; left: 50%; transform: translate(-50%,-50%); font-size: 32rpx; font-weight: bold; }
11	.progress-num { font-size: 44rpx; font-weight: bold; }
12	.progress-label { font-size: 24rpx; color: #78716c; }
13	.domain-title { font-size: 26rpx; color: #78716c; margin: 32rpx 0 16rpx; }
14	.habit-item {
15	  background: #fff; border-radius: 20rpx; padding: 28rpx; margin-bottom: 12rpx;
16	  display: flex; align-items: center; gap: 20rpx;
17	  box-shadow: 0 2rpx 12rpx rgba(0,0,0,0.03);
18	}
19	.habit-item.done { opacity: 0.5; background: #f5f3f0; }
20	.habit-text { flex: 1; }
21	.habit-name { font-size: 30rpx; font-weight: 500; }
22	.habit-name.done { text-decoration: line-through; color: #78716c; }
23	.habit-desc { font-size: 22rpx; color: #78716c; margin-top: 4rpx; }
24	.habit-unit { font-size: 22rpx; color: #a8a29e; }
25	.check-icon { width: 44rpx; height: 44rpx; border-radius: 50%; border: 3rpx solid #d6d3d1; flex-shrink: 0; }
26	.check-icon.checked { background: #10b981; border-color: #10b981; display: flex; align-items: center; justify-content: center; color: #fff; font-size: 24rpx; }
27	.empty { text-align: center; padding: 80rpx 0; color: #a8a29e; }
